node_36.code:
for instance in instances:
    result = process_instance(instance, config, output_dir, model_name, mode_name)
    results.append(result)

node_39.code:
with concurrent.futures.ThreadPoolExecutor(max_workers=workers) as executor:
    futures = {executor.submit(process_instance, instance, config, output_dir, model_name, mode_name): instance['instance_id'] for instance in instances}
    for future in concurrent.futures.as_completed(futures):
        try:
            results.append(future.result())
        except Exception as e:
            iid = futures[future]
            logger.error(f'[{run_id}] Uncaught error for {iid}: {e}')

